var html = $input.item.json.body || $input.item.json.data || '';
var statusCode = $input.item.json.statusCode || 200;
var loopData = $('Loop Companies1').item.json;
var editFieldsData = $('Edit Fields').item.json;
var company = editFieldsData.companyName || loopData.companyName || 'Unknown';

// Check if blocked or error
if (statusCode === 403 || statusCode === 429) {
  return {
    company: company,
    g2Data: 'G2: Blocked (anti-bot protection)',
    g2Found: false,
    g2Rating: null,
    g2ReviewsCount: 0,
    g2Error: 'Access blocked by G2',
    g2StatusCode: statusCode
  };
}

if (!html || html.length < 1000) {
  return {
    company: company,
    g2Data: 'G2: No data received',
    g2Found: false,
    g2Rating: null,
    g2ReviewsCount: 0,
    g2Error: 'Empty response',
    g2StatusCode: statusCode
  };
}

// Multiple patterns to find rating
var ratingPatterns = [
  /(\d+\.\d+)\s*out of 5/i,
  /(\d+\.\d+)\s*\/\s*5/i,
  /"rating"\s*:\s*(\d+\.?\d*)/i,
  /"ratingValue"\s*:\s*"?(\d+\.?\d*)/i,
  /data-rating="(\d+\.?\d*)"/i,
  /class="[^"]*star[^"]*"[^>]*>(\d+\.?\d*)/i,
  /average[\s\-_]?rating["\s:>]*(\d+\.?\d*)/i
];

var reviewPatterns = [
  /(\d+[,\d]*)\s*reviews?/i,
  /(\d+[,\d]*)\s*ratings?/i,
  /"reviewCount"\s*:\s*"?(\d+)/i,
  /"ratingCount"\s*:\s*"?(\d+)/i,
  /(\d+[,\d]*)\s*verified/i
];

var rating = null;
var reviewsCount = null;
var productName = null;
var productUrl = null;

// Try to find rating
for (var i = 0; i < ratingPatterns.length; i++) {
  var match = html.match(ratingPatterns[i]);
  if (match && match[1]) {
    var num = parseFloat(match[1]);
    if (num > 0 && num <= 5) {
      rating = num;
      break;
    }
  }
}

// Try to find reviews count
for (var j = 0; j < reviewPatterns.length; j++) {
  var match = html.match(reviewPatterns[j]);
  if (match && match[1]) {
    reviewsCount = parseInt(match[1].replace(/,/g, ''));
    if (reviewsCount > 0) break;
  }
}

// Try to find product name
var nameMatch = html.match(/<h1[^>]*>([^<]+)<\/h1>/i) ||
                html.match(/"name"\s*:\s*"([^"]+)"/i) ||
                html.match(/class="product-name[^"]*"[^>]*>([^<]+)/i);
if (nameMatch) {
  productName = nameMatch[1].trim();
}

// Try to find product URL on G2
var urlMatch = html.match(/href="(\/products\/[^"]+)"/i) ||
               html.match(/href="(https:\/\/www\.g2\.com\/products\/[^"]+)"/i);
if (urlMatch) {
  productUrl = urlMatch[1].startsWith('http') ? urlMatch[1] : 'https://www.g2.com' + urlMatch[1];
}

// Check if we found the company in search results
var companyLower = company.toLowerCase().replace(/[-_\s]/g, '');
var foundInResults = html.toLowerCase().includes(companyLower) ||
                     html.toLowerCase().includes(company.toLowerCase());

if (!rating && !foundInResults) {
  return {
    company: company,
    g2Data: 'G2: Not found in search results',
    g2Found: false,
    g2Rating: null,
    g2ReviewsCount: 0,
    g2ProductName: null,
    g2ProductUrl: null,
    g2SearchPerformed: true
  };
}

var g2Summary = '';
if (rating) {
  g2Summary = 'G2: ' + rating.toFixed(1) + '/5';
  if (reviewsCount) {
    g2Summary += ' (' + reviewsCount + ' reviews)';
  }
  if (productName) {
    g2Summary += ' - ' + productName;
  }
} else if (foundInResults) {
  g2Summary = 'G2: Found but no rating available';
} else {
  g2Summary = 'G2: Not found';
}

return {
  company: company,
  g2Data: g2Summary,
  g2Found: !!rating || foundInResults,
  g2Rating: rating,
  g2ReviewsCount: reviewsCount || 0,
  g2ProductName: productName,
  g2ProductUrl: productUrl,
  g2SearchPerformed: true
};

var g2 = $input.item.json;
var loopData = $('Loop Companies1').item.json;
var editFieldsData = $('Edit Fields').item.json;
var company = editFieldsData.companyName || loopData.companyName || 'Unknown';

// Build comprehensive aggregator summary
var aggregatorData = [];

// G2 data
if (g2.g2Found) {
  aggregatorData.push({
    platform: 'G2',
    rating: g2.g2Rating,
    reviewsCount: g2.g2ReviewsCount,
    productName: g2.g2ProductName,
    productUrl: g2.g2ProductUrl,
    summary: g2.g2Data
  });
}

// Create summary string
var aggregatorMentions = g2.g2Data || 'No aggregator data found';

return {
  company: company,
  aggregatorMentions: aggregatorMentions,
  g2Rating: g2.g2Rating || null,
  g2ReviewsCount: g2.g2ReviewsCount || 0,
  g2ProductUrl: g2.g2ProductUrl || null,
  g2Found: g2.g2Found || false,
  aggregatorData: aggregatorData
};

var websiteHtml = $('Fetch Website1').item.json.body || $('Fetch Website1').item.json.data || '';
var loopData = $('Loop Companies1').item.json;
var editFieldsData = $('Edit Fields').item.json;
var companyName = editFieldsData.companyName || loopData.companyName || 'Unknown';

var youtubePatterns = [
  { pattern: /youtube\.com\/channel\/([a-zA-Z0-9_-]+)/i, type: 'channelId' },
  { pattern: /youtube\.com\/c\/([a-zA-Z0-9_-]+)/i, type: 'customUrl' },
  { pattern: /youtube\.com\/user\/([a-zA-Z0-9_-]+)/i, type: 'username' },
  { pattern: /youtube\.com\/@([a-zA-Z0-9_-]+)/i, type: 'handle' },
  { pattern: /youtube\.com\/([a-zA-Z][a-zA-Z0-9_-]{2,})(?:[\/"'\s\?]|$)/i, type: 'legacyUsername' }
];

var excludeWords = ['watch', 'embed', 'playlist', 'results', 'feed', 'gaming',
  'premium', 'music', 'kids', 'tv', 'shorts', 'live', 'about', 'redirect',
  'howyoutubeworks', 'yt', 'creators', 'ads', 'upload', 'attribution_link',
  'channel', 'user', 'c', 'hashtag', 'trending', 'subscription', 'account'];

var channelId = null;
var channelHandle = null;
var youtubeUrl = null;
var matchType = null;

for (var i = 0; i < youtubePatterns.length; i++) {
  var match = websiteHtml.match(youtubePatterns[i].pattern);
  if (match && match[1] && excludeWords.indexOf(match[1].toLowerCase()) === -1) {
    channelHandle = match[1];
    matchType = youtubePatterns[i].type;

    if (matchType === 'channelId') {
      youtubeUrl = 'https://www.youtube.com/channel/' + channelHandle;
      channelId = channelHandle;
    } else if (matchType === 'handle') {
      youtubeUrl = 'https://www.youtube.com/@' + channelHandle;
    } else {
      youtubeUrl = 'https://www.youtube.com/' + channelHandle;
    }
    break;
  }
}

return {
  company: companyName,
  youtubeChannelId: channelId,
  youtubeHandle: channelHandle,
  youtubeUrl: youtubeUrl,
  autoDetected: !!channelHandle,
  matchType: matchType
};

var response = $input.item.json;
var resolveData = $('Resolve YouTube ChannelId').item.json;
var autoDetectData = $('Auto-detect YouTube Channel1').item.json;
var loopData = $('Loop Companies1').item.json;
var editFieldsData = $('Edit Fields').item.json;
var company = editFieldsData.companyName || loopData.companyName || 'Unknown';

// If channel not found on site
if (!autoDetectData.autoDetected) {
  return {
    company: company,
    youtubeActivity: 'YouTube channel not found on site',
    youtubeVideoCount: 0,
    youtubeUrl: null
  };
}

// If channel resolve failed
if (!resolveData.items || resolveData.items.length === 0) {
  return {
    company: company,
    youtubeActivity: 'YouTube channel could not be resolved: ' + autoDetectData.youtubeHandle,
    youtubeVideoCount: 0,
    youtubeUrl: autoDetectData.youtubeUrl
  };
}

// If no videos in response
if (!response.items || response.items.length === 0) {
  return {
    company: company,
    youtubeActivity: 'No new videos this week',
    youtubeVideoCount: 0,
    youtubeUrl: autoDetectData.youtubeUrl,
    youtubeChannelName: resolveData.items[0].snippet.title
  };
}

var videos = response.items;
var videoCount = videos.length;
var latestVideo = videos[0];
var channelInfo = resolveData.items[0];

return {
  company: company,
  youtubeActivity: videoCount + ' new videos. Latest: "' + latestVideo.snippet.title + '" (' + latestVideo.snippet.publishedAt.split('T')[0] + ')',
  youtubeVideoCount: videoCount,
  youtubeUrl: autoDetectData.youtubeUrl,
  youtubeChannelName: channelInfo.snippet.title,
  youtubeVideos: videos.slice(0, 3).map(function(v) {
    return {
      title: v.snippet.title,
      publishedAt: v.snippet.publishedAt,
      url: 'https://www.youtube.com/watch?v=' + v.id.videoId
    };
  })
};

var websiteHtml = $('Fetch Website1').item.json.body || $('Fetch Website1').item.json.data || '';
var loopData = $('Loop Companies1').item.json;
var editFieldsData = $('Edit Fields').item.json;
var company = editFieldsData.companyName || loopData.companyName || 'Unknown';

// Helper function to extract URL
function extractUrl(html, pattern) {
  var match = html.match(pattern);
  return match ? match[0] : null;
}

// Helper to extract all matches
function extractAllUrls(html, pattern) {
  var matches = html.match(new RegExp(pattern.source, 'gi')) || [];
  return [...new Set(matches)]; // unique values
}

// Social media patterns - including Russian/CIS platforms
var patterns = {
  // International
  linkedin: /linkedin\.com\/(?:company|in)\/[a-zA-Z0-9_-]+/i,
  facebook: /facebook\.com\/[a-zA-Z0-9._-]+/i,
  twitter: /(?:twitter|x)\.com\/[a-zA-Z0-9_]+/i,
  instagram: /instagram\.com\/[a-zA-Z0-9._]+/i,
  youtube: /youtube\.com\/(?:channel\/|c\/|user\/|@)?[a-zA-Z0-9_-]+/i,

  // Russian/CIS platforms
  vk: /vk\.com\/[a-zA-Z0-9._-]+/i,
  telegram: /t\.me\/[a-zA-Z0-9_]+/i,
  ok: /ok\.ru\/[a-zA-Z0-9._-]+/i,
  dzen: /(?:dzen|zen)\.yandex\.ru\/[a-zA-Z0-9._-]+/i,
  rutube: /rutube\.ru\/(?:channel|video)\/[a-zA-Z0-9_-]+/i,

  // Other
  tiktok: /tiktok\.com\/@[a-zA-Z0-9._-]+/i,
  whatsapp: /(?:wa\.me|whatsapp\.com)\/[a-zA-Z0-9_+-]+/i,
  viber: /viber\.com\/[a-zA-Z0-9_-]+/i
};

// Exclude patterns (not real social profiles)
var excludePatterns = {
  youtube: /youtube\.com\/(watch|embed|playlist|results|feed|channel\/|c\/|user\/|@)?$/i,
  facebook: /facebook\.com\/(sharer|share|dialog|plugins)/i,
  twitter: /twitter\.com\/(intent|share)/i
};

var results = {
  company: company
};

// Extract all social links
for (var platform in patterns) {
  var url = extractUrl(websiteHtml, patterns[platform]);

  // Check if it's not an exclude pattern
  if (url && excludePatterns[platform] && excludePatterns[platform].test(url)) {
    url = null;
  }

  results[platform] = url;
}

// Count found links
var foundLinks = Object.keys(results).filter(function(key) {
  return key !== 'company' && results[key] !== null;
});

results.socialLinksCount = foundLinks.length;
results.foundPlatforms = foundLinks;

return results;

var data = $input.item.json;
var loopData = $('Loop Companies1').item.json;
var editFieldsData = $('Edit Fields').item.json;
var company = editFieldsData.companyName || loopData.companyName || 'Unknown';

var activities = [];

// International platforms
if (data.linkedin) activities.push('LinkedIn: ' + data.linkedin);
if (data.facebook) activities.push('Facebook: ' + data.facebook);
if (data.twitter) activities.push('Twitter/X: ' + data.twitter);
if (data.instagram) activities.push('Instagram: ' + data.instagram);
if (data.youtube) activities.push('YouTube: ' + data.youtube);
if (data.tiktok) activities.push('TikTok: ' + data.tiktok);

// Russian/CIS platforms
if (data.vk) activities.push('VK: ' + data.vk);
if (data.telegram) activities.push('Telegram: ' + data.telegram);
if (data.ok) activities.push('OK.ru: ' + data.ok);
if (data.dzen) activities.push('Dzen: ' + data.dzen);
if (data.rutube) activities.push('RuTube: ' + data.rutube);

// Messengers
if (data.whatsapp) activities.push('WhatsApp: ' + data.whatsapp);
if (data.viber) activities.push('Viber: ' + data.viber);

return {
  company: company,
  linkedinActivity: data.linkedin ? 'LinkedIn: ' + data.linkedin : '-',
  facebookActivity: data.facebook ? 'Facebook: ' + data.facebook : '-',
  vkActivity: data.vk ? 'VK: ' + data.vk : '-',
  telegramActivity: data.telegram ? 'Telegram: ' + data.telegram : '-',
  youtubeActivity: data.youtube ? 'YouTube: ' + data.youtube : '-',
  allSocialLinks: activities.length > 0 ? activities.join('; ') : '-',
  socialLinksCount: data.socialLinksCount || 0,
  foundPlatforms: data.foundPlatforms || []
};

// Extract & Filter URLs - V2 Ð· Ñ€Ð¾Ð·ÑˆÐ¸Ñ€ÐµÐ½Ð¸Ð¼Ð¸ Ð¿Ð°Ñ‚Ñ‚ÐµÑ€Ð½Ð°Ð¼Ð¸
var scanResult = $input.item.json;
var allResults = scanResult.all_results || [];
var editFieldsData = $('Edit Fields').first().json;
var companyName = editFieldsData.companyName || 'Unknown';
var companyUrl = editFieldsData.companyUrl || '';
console.log('Extract URLs - Company:', companyName, 'Total URLs:', allResults.length);
var categories = {
blog: /\/(blog|blogs|article|articles|post|posts|insights|journal|novosti|stati|publikacii)/i,
news: /\/(news|press|announcements|newsroom|events|meropriyatiya|sobytiya)/i,
reviews: /\/(review|reviews|testimonial|testimonials|customer-stories|success-stories|case-studies|otzyvy|klienty|use_mango|clients)/i,
pricing: /\/(pricing|price|prices|plans|tarif|cost|tariffs|ceny|stoimost)/i,
features: /\/(features|feature|capabilities|vozmozhnosti|resheniya|funktsii|marketplace|integraciya)/i
};
var categorizedUrls = [];
var seenUrls = new Set();
for (var i = 0; i < allResults.length; i++) {
var result = allResults[i];
var url = result.url || '';
if (result.has_errors || seenUrls.has(url)) continue;
seenUrls.add(url);
if (url.match(/\/$/)) {
var path = url.replace(/https?:\/\/[^\/]+/, '');
if (path === '/' || path === '/about/' || path === '/promo/' || path === '/products/') continue;
}
for (var cat in categories) {
if (categories[cat].test(url)) {
categorizedUrls.push({
url: url,
category: cat,
status_code: result.status_code,
companyName: companyName,
companyUrl: companyUrl
});
break;
}
}
}
console.log('Filtered URLs:', categorizedUrls.length, 'Categories:', categorizedUrls.map(function(u) { return u.category; }).join(', '));
if (categorizedUrls.length === 0) {
return [{ json: { url: '', category: 'none', status_code: 0, companyName: companyName, companyUrl: companyUrl } }];
}
return categorizedUrls.map(function(item) { return { json: item }; });

// Parse Page Content - V4 (fixed: data instead of body)
var inputItem = $input.item.json;
var html = inputItem.data || inputItem.body || '';
var setFieldsData = $('Set Fields Before Fetch').item.json;
var companyName = setFieldsData.companyName || 'Unknown';
var companyUrl = setFieldsData.companyUrl || '';
var pageUrl = setFieldsData.pageUrl || '';
var category = setFieldsData.category || 'unknown';
function cleanText(text) {
if (!text) return '';
return text.replace(/&nbsp;/gi, ' ').replace(/&amp;/gi, '&').replace(/&lt;/gi, '<').replace(/&gt;/gi, '>').replace(/&#\d+;/g, '').replace(/\s+/g, ' ').trim();
}
var cleanHtml = html.replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '').replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '').replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '').replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '').replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '').replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
var titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
var title = titleMatch ? cleanText(titleMatch[1]) : null;
var descMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i);
var description = descMatch ? cleanText(descMatch[1]) : null;
var h1Matches = cleanHtml.match(/<h1[^>]*>([\s\S]*?)<\/h1>/gi) || [];
var h2Matches = cleanHtml.match(/<h2[^>]*>([\s\S]*?)<\/h2>/gi) || [];
var h3Matches = cleanHtml.match(/<h3[^>]*>([\s\S]*?)<\/h3>/gi) || [];
var h1Tags = h1Matches.map(function(h) { return cleanText(h.replace(/<[^>]+>/g, '')); }).filter(function(t) { return t.length > 2 && t.length < 200; });
var h2Tags = h2Matches.map(function(h) { return cleanText(h.replace(/<[^>]+>/g, '')); }).filter(function(t) { return t.length > 5 && t.length < 200; }).slice(0, 10);
var h3Tags = h3Matches.map(function(h) { return cleanText(h.replace(/<[^>]+>/g, '')); }).filter(function(t) { return t.length > 5 && t.length < 200; }).slice(0, 15);
var categoryData = {};
if (category === 'blog' || category === 'news') {
var articles = [];
var seen = new Set();
var articlePatterns = [/<article[^>]*>([\s\S]*?)<\/article>/gi, /<div[^>]*class=["'][^"']*(?:post|entry|blog-item|news-item|article)[^"']*["'][^>]*>([\s\S]*?)<\/div>/gi];
for (var p = 0; p < articlePatterns.length && articles.length < 15; p++) {
var match;
articlePatterns[p].lastIndex = 0;
while ((match = articlePatterns[p].exec(cleanHtml)) !== null && articles.length < 15) {
var content = match[1] || match[0];
var tMatch = content.match(/<h[1-4][^>]*>([\s\S]*?)<\/h[1-4]>/i);
var t = tMatch ? cleanText(tMatch[1].replace(/<[^>]+>/g, '')) : null;
if (t && t.length > 10 && !seen.has(t.toLowerCase())) {
seen.add(t.toLowerCase());
articles.push({ title: t, preview: cleanText(content.replace(/<[^>]+>/g, ' ')).substring(0, 200) });
}
}
}
if (articles.length === 0) {
h2Tags.concat(h3Tags).forEach(function(t) {
if (!seen.has(t.toLowerCase()) && articles.length < 15) {
seen.add(t.toLowerCase());
articles.push({ title: t, preview: '' });
}
});
}
categoryData.articles = articles;
categoryData.topics = h2Tags.slice(0, 10);
} else if (category === 'reviews') {
categoryData.topics = h2Tags.concat(h3Tags).slice(0, 15);
categoryData.mainContent = cleanText(cleanHtml.replace(/<[^>]+>/g, ' ')).substring(0, 1000);
} else if (category === 'pricing') {
var priceMatches = html.match(/\d+[\s\u00a0]*(?:Ñ€ÑƒÐ±|â‚½|Ñ€ÑƒÐ±Ð»ÐµÐ¹|RUB)|[\$â‚¬Â£]\s*\d+(?:[.,]\d{2})?|\d+(?:[.,]\d{2})?\s*(?:USD|EUR|GBP|Ñ€ÑƒÐ±)/gi) || [];
categoryData.prices = [...new Set(priceMatches)].slice(0, 20);
categoryData.hasPricing = priceMatches.length > 0;
categoryData.plans = h2Tags.concat(h3Tags).filter(function(t) { return t.match(/Ð¿Ð°ÐºÐµÑ‚|Ñ‚Ð°Ñ€Ð¸Ñ„|Ð¿Ð»Ð°Ð½|price|plan|Ð±Ð°Ð·Ð¾Ð²|ÑÑ‚Ð°Ð½Ð´Ð°Ñ€Ñ‚|Ð¿Ñ€ÐµÐ¼Ð¸ÑƒÐ¼|pro|enterprise/i); }).slice(0, 10);
categoryData.topics = h2Tags.slice(0, 10);
} else if (category === 'features') {
var features = [];
var featureLists = cleanHtml.match(/<ul[^>]*>[\s\S]{1,10000}?<\/ul>/gi) || [];
for (var j = 0; j < featureLists.length && features.length < 30; j++) {
var items = featureLists[j].match(/<li[^>]*>([\s\S]*?)<\/li>/gi) || [];
for (var k = 0; k < items.length && features.length < 30; k++) {
var text = cleanText(items[k].replace(/<[^>]+>/g, ''));
if (text.length > 10 && text.length < 300) features.push(text);
}
}
categoryData.features = features;
categoryData.topics = h2Tags.concat(h3Tags).slice(0, 15);
}
var mainText = cleanText(cleanHtml.replace(/<[^>]+>/g, ' ')).substring(0, 1500);
return {
url: pageUrl,
category: category,
companyName: companyName,
companyUrl: companyUrl,
metadata: { title: title, description: description, h1: h1Tags, h2: h2Tags, h3: h3Tags },
content: categoryData,
summary: mainText,
parsedAt: new Date().toISOString()
};

// Aggregate by Category - FIXED VERSION
// Збирає всі розпарсені сторінки в один об'єкт для AI Agent

const allPages = $input.all();

// Отримуємо дані компанії
let companyName = 'Unknown';
let companyUrl = '';

if (allPages.length > 0 && allPages[0].json) {
  companyName = allPages[0].json.companyName || allPages[0].json.company || 'Unknown';
  companyUrl = allPages[0].json.companyUrl || allPages[0].json.url || '';
}

// Категоризуємо сторінки
const byCategory = {
  blog: [],
  news: [],
  reviews: [],
  pricing: [],
  features: []
};

for (const page of allPages) {
  const pageData = page.json;
  const category = pageData.category || 'other';
  if (byCategory[category]) {
    byCategory[category].push({
      url: pageData.url || '',
      title: pageData.title || '',
      description: pageData.description || '',
      content: (pageData.content || '').substring(0, 500)
    });
  }
}

// Статистика
const stats = {};
for (const cat in byCategory) {
  stats[cat] = byCategory[cat].length;
}

// Формуємо структуру даних для AI Agent
return {
  json: {
    company: companyName,
    url: companyUrl,
    currentData: {
      website: {
        title: byCategory.features[0]?.title || byCategory.blog[0]?.title || '-',
        description: byCategory.features[0]?.description || byCategory.blog[0]?.description || '-'
      },
      blog: {
        articlesFound: byCategory.blog.length,
        articles: byCategory.blog.slice(0, 5)
      },
      news: {
        count: byCategory.news.length,
        items: byCategory.news.slice(0, 3)
      },
      reviews: {
        count: byCategory.reviews.length,
        items: byCategory.reviews.slice(0, 3)
      },
      pricing: byCategory.pricing[0] || null,
      features: byCategory.features.slice(0, 3)
    },
    totalPagesParsed: allPages.length,
    statistics: stats,
    aggregatedAt: new Date().toISOString()
  }
};

var response = $input.item.json;
var rawContent = response.output || response.text || '';
if (response.choices && response.choices[0] && response.choices[0].message) {
  rawContent = response.choices[0].message.content;
}
rawContent = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
var parsedData;
try {
  parsedData = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (e) {
